<?php require_once __DIR__.'/includes/functions.php';if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$ref=make_ref('FHBF-MEM');db()->prepare("INSERT INTO membership_applications(reference,full_name,email,phone,membership_type,business_name,industry,seven_mountain,province,directory_consent,payment_reference,status) VALUES(?,?,?,?,?,?,?,?,?,?,?,'Submitted')")->execute([$ref,$_POST['full_name'],$_POST['email'],$_POST['phone'],$_POST['membership_type'],$_POST['business_name']??'',$_POST['industry']??'',$_POST['seven_mountain']??'',$_POST['province']??'',isset($_POST['directory_consent'])?1:0,$_POST['payment_reference']??'']);flash('success',"Application received. Reference: $ref");redirect('/membership.php');}include __DIR__.'/includes/header.php';$tiers=db()->query("SELECT * FROM membership_types WHERE active=1 ORDER BY sort_order,id")->fetchAll();?><section class="section"><h1>Membership</h1><div class="grid"><?php foreach($tiers as $t): ?><div class="card"><h3><?=h($t['name'])?></h3><div class="price">US$<?=h($t['annual_fee'])?></div><p><?=h($t['description'])?></p></div><?php endforeach; ?></div><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><h2>Apply Now</h2><label>Full Name<input name="full_name" required></label><label>Email<input name="email" type="email" required></label><label>Phone<input name="phone" required></label><label>Membership Type<select name="membership_type"><?php foreach($tiers as $t): ?><option><?=h($t['name'])?></option><?php endforeach; ?></select></label><label>Business Name<input name="business_name"></label><label>Industry<input name="industry"></label><label>Seven Mountain<input name="seven_mountain"></label><label>Province / City<input name="province"></label><label>Payment Reference<input name="payment_reference"></label><label><input type="checkbox" name="directory_consent" style="width:auto"> Include in directory</label><button>Submit Application</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>